// SPDX-License-Identifier: MIT
pragma solidity ^0.8.27;

/**
 * @title SupplyChain
 * @notice Σύστημα ιχνηλάτησης προϊόντων εφοδιαστικής αλυσίδας με blockchain.
 * @dev Υλοποιεί ρόλους χρηστών, καταχώρηση παρτίδων, παρακολούθηση
 *      διαδρομής και πιστοποίηση μέσω Ελεγκτή / Ρυθμιστικής Αρχής.
 */
contract SupplyChain {

    // =========================================================================
    //  Enums
    // =========================================================================

    /// @notice Ρόλοι χρηστών στο σύστημα
    enum Role {
        None,           // 0 - Μη εγγεγραμμένος
        Admin,          // 1 - Διαχειριστής
        Producer,       // 2 - Παραγωγός
        Transporter,    // 3 - Μεταφορέας
        Warehouse,      // 4 - Αποθήκη / Κέντρο Διανομής
        Distributor,    // 5 - Διανομέας / Λιανοπωλητής
        Regulator       // 6 - Ελεγκτής / Ρυθμιστική Αρχή
    }

    /// @notice Κατάσταση (στάδιο) μιας παρτίδας
    enum Status {
        Produced,       // 0 - Παραγωγή
        Stored,         // 1 - Αποθήκευση
        InTransit,      // 2 - Μεταφορά
        Delivered       // 3 - Διάθεση στον καταναλωτή / σημείο πώλησης
    }

    /// @notice Κατηγορία προϊόντος
    enum Category {
        Perishable,     // 0 - Ευπαθές
        NonPerishable   // 1 - Μη ευπαθές
    }

    // =========================================================================
    //  Structs
    // =========================================================================

    /// @notice Δομή δεδομένων χρήστη
    struct User {
        address userAddress;    // Ethereum address
        string  name;           // Όνομα χρήστη
        Role    role;           // Ρόλος
        bool    active;         // Ενεργός / ανενεργός
    }

    /// @notice Δομή δεδομένων παρτίδας προϊόντος
    struct Batch {
        uint256   id;              // Μοναδικό αναγνωριστικό
        string    productType;     // Τύπος προϊόντος (π.χ. "Ελαιόλαδο")
        Category  category;        // Ευπαθές / Μη ευπαθές
        string    origin;          // Τοποθεσία προέλευσης
        uint256   creationDate;    // Ημερομηνία δημιουργίας (block.timestamp)
        Status    status;          // Τρέχον στάδιο
        address   currentHolder;   // Ποιος κατέχει τη παρτίδα τώρα
        bool      certified;       // Πιστοποιημένη από Ελεγκτή
        address   producer;        // Αρχικός παραγωγός
    }

    /// @notice Σημείο ελέγχου (checkpoint) στη διαδρομή μιας παρτίδας
    struct Checkpoint {
        uint256 timestamp;     // Χρονοσήμανση
        string  location;      // Τοποθεσία
        address handler;       // Ποιος έκανε την ενέργεια
        Status  status;        // Νέο στάδιο
        string  notes;         // Σημειώσεις
    }

    // =========================================================================
    //  State Variables
    // =========================================================================

    address public admin;                           // Λογαριασμός διαχειριστή
    uint256 public batchCount;                      // Μετρητής παρτίδων

    mapping(address => User)       public users;            // address → User
    mapping(uint256 => Batch)      public batches;          // batchId → Batch
    mapping(uint256 => Checkpoint[]) public batchHistory;   // batchId → Checkpoint[]

    address[] public userAddresses;                 // Λίστα διευθύνσεων χρηστών
    uint256[] public batchIds;                      // Λίστα IDs παρτίδων

    // =========================================================================
    //  Events (Logging κρίσιμων ενεργειών)
    // =========================================================================

    event UserRegistered(address indexed user, string name, Role role);
    event UserDeactivated(address indexed user);
    event BatchCreated(uint256 indexed batchId, address indexed producer, string productType);
    event BatchStatusUpdated(uint256 indexed batchId, Status newStatus, address indexed updatedBy, string location);
    event BatchTransferred(uint256 indexed batchId, address indexed from, address indexed to);
    event BatchCertified(uint256 indexed batchId, address indexed regulator);

    // =========================================================================
    //  Modifiers (Έλεγχος πρόσβασης)
    // =========================================================================

    /// @notice Μόνο ο Διαχειριστής
    modifier onlyAdmin() {
        require(msg.sender == admin, "Access denied: only Admin");
        _;
    }

    /// @notice Μόνο ενεργός εγγεγραμμένος χρήστης
    modifier onlyRegistered() {
        require(users[msg.sender].active, "Access denied: not registered or inactive");
        _;
    }

    /// @notice Μόνο Παραγωγός
    modifier onlyProducer() {
        require(
            users[msg.sender].role == Role.Producer && users[msg.sender].active,
            "Access denied: only Producer"
        );
        _;
    }

    /// @notice Μόνο Μεταφορέας
    modifier onlyTransporter() {
        require(
            users[msg.sender].role == Role.Transporter && users[msg.sender].active,
            "Access denied: only Transporter"
        );
        _;
    }

    /// @notice Μόνο Αποθήκη / Κέντρο Διανομής
    modifier onlyWarehouse() {
        require(
            users[msg.sender].role == Role.Warehouse && users[msg.sender].active,
            "Access denied: only Warehouse"
        );
        _;
    }

    /// @notice Μόνο Διανομέας / Λιανοπωλητής
    modifier onlyDistributor() {
        require(
            users[msg.sender].role == Role.Distributor && users[msg.sender].active,
            "Access denied: only Distributor"
        );
        _;
    }

    /// @notice Μόνο Ελεγκτής / Ρυθμιστική Αρχή
    modifier onlyRegulator() {
        require(
            users[msg.sender].role == Role.Regulator && users[msg.sender].active,
            "Access denied: only Regulator"
        );
        _;
    }

    /// @notice Μόνο ο τρέχων κάτοχος της παρτίδας
    modifier onlyCurrentHolder(uint256 _batchId) {
        require(batches[_batchId].currentHolder == msg.sender, "Access denied: not current holder");
        _;
    }

    // =========================================================================
    //  Constructor
    // =========================================================================

    /**
     * @notice Ο deployer γίνεται αυτόματα Admin.
     */
    constructor() {
        admin = msg.sender;
        users[msg.sender] = User({
            userAddress: msg.sender,
            name: "Admin",
            role: Role.Admin,
            active: true
        });
        userAddresses.push(msg.sender);
        emit UserRegistered(msg.sender, "Admin", Role.Admin);
    }

    // =========================================================================
    //  Διαχείριση Χρηστών
    // =========================================================================

    /**
     * @notice Εγγραφή νέου χρήστη στο σύστημα (μόνο από Admin).
     * @param _userAddress Διεύθυνση Ethereum χρήστη
     * @param _name        Όνομα χρήστη
     * @param _role        Ρόλος (1-6)
     */
    function registerUser(
        address _userAddress,
        string calldata _name,
        Role _role
    ) external onlyAdmin {
        require(_userAddress != address(0), "Invalid address");
        require(_role != Role.None, "Role cannot be None");
        require(!users[_userAddress].active, "User already registered");

        users[_userAddress] = User({
            userAddress: _userAddress,
            name: _name,
            role: _role,
            active: true
        });
        userAddresses.push(_userAddress);

        emit UserRegistered(_userAddress, _name, _role);
    }

    /**
     * @notice Απενεργοποίηση χρήστη (μόνο από Admin).
     * @param _userAddress Διεύθυνση χρήστη προς απενεργοποίηση
     */
    function deactivateUser(address _userAddress) external onlyAdmin {
        require(users[_userAddress].active, "User not active");
        require(_userAddress != admin, "Cannot deactivate admin");
        users[_userAddress].active = false;
        emit UserDeactivated(_userAddress);
    }

    // =========================================================================
    //  Διαχείριση Παρτίδων
    // =========================================================================

    /**
     * @notice Δημιουργία νέας παρτίδας (μόνο από Παραγωγό).
     * @param _productType Τύπος προϊόντος
     * @param _category    Κατηγορία (0=Ευπαθές, 1=Μη ευπαθές)
     * @param _origin      Τοποθεσία προέλευσης
     * @return batchId     Το μοναδικό ID της νέας παρτίδας
     */
    function createBatch(
        string calldata _productType,
        Category _category,
        string calldata _origin
    ) external onlyProducer returns (uint256 batchId) {
        batchCount++;
        batchId = batchCount;

        batches[batchId] = Batch({
            id: batchId,
            productType: _productType,
            category: _category,
            origin: _origin,
            creationDate: block.timestamp,
            status: Status.Produced,
            currentHolder: msg.sender,
            certified: false,
            producer: msg.sender
        });
        batchIds.push(batchId);

        // Πρώτο checkpoint: δημιουργία
        batchHistory[batchId].push(Checkpoint({
            timestamp: block.timestamp,
            location: _origin,
            handler: msg.sender,
            status: Status.Produced,
            notes: "Batch created by producer"
        }));

        emit BatchCreated(batchId, msg.sender, _productType);
    }

    /**
     * @notice Ενημέρωση κατάστασης παρτίδας (μόνο από τον τρέχοντα κάτοχο
     *         και με κατάλληλο ρόλο).
     * @param _batchId   ID παρτίδας
     * @param _newStatus Νέα κατάσταση
     * @param _location  Τοποθεσία
     * @param _notes     Σημειώσεις
     */
    function updateBatchStatus(
        uint256 _batchId,
        Status _newStatus,
        string calldata _location,
        string calldata _notes
    ) external onlyRegistered onlyCurrentHolder(_batchId) {
        require(_batchId > 0 && _batchId <= batchCount, "Batch does not exist");

        Batch storage batch = batches[_batchId];
        Role senderRole = users[msg.sender].role;

        // Έλεγχος ότι ο ρόλος ταιριάζει με τη νέα κατάσταση
        if (_newStatus == Status.Stored) {
            require(
                senderRole == Role.Warehouse || senderRole == Role.Producer,
                "Only Warehouse or Producer can set Stored"
            );
        } else if (_newStatus == Status.InTransit) {
            require(
                senderRole == Role.Transporter,
                "Only Transporter can set InTransit"
            );
        } else if (_newStatus == Status.Delivered) {
            require(
                senderRole == Role.Distributor,
                "Only Distributor can set Delivered"
            );
        }

        batch.status = _newStatus;

        batchHistory[_batchId].push(Checkpoint({
            timestamp: block.timestamp,
            location: _location,
            handler: msg.sender,
            status: _newStatus,
            notes: _notes
        }));

        emit BatchStatusUpdated(_batchId, _newStatus, msg.sender, _location);
    }

    /**
     * @notice Μεταβίβαση παρτίδας σε νέο κάτοχο (μόνο από τον τρέχοντα κάτοχο).
     * @param _batchId    ID παρτίδας
     * @param _newHolder  Νέα διεύθυνση κατόχου
     */
    function transferBatch(
        uint256 _batchId,
        address _newHolder
    ) external onlyRegistered onlyCurrentHolder(_batchId) {
        require(_batchId > 0 && _batchId <= batchCount, "Batch does not exist");
        require(users[_newHolder].active, "New holder is not a registered user");
        require(_newHolder != msg.sender, "Cannot transfer to yourself");

        address previousHolder = batches[_batchId].currentHolder;
        batches[_batchId].currentHolder = _newHolder;

        emit BatchTransferred(_batchId, previousHolder, _newHolder);
    }

    /**
     * @notice Πιστοποίηση παρτίδας (μόνο από Ελεγκτή / Ρυθμιστική Αρχή).
     * @param _batchId ID παρτίδας
     */
    function certifyBatch(uint256 _batchId) external onlyRegulator {
        require(_batchId > 0 && _batchId <= batchCount, "Batch does not exist");
        require(!batches[_batchId].certified, "Batch already certified");

        batches[_batchId].certified = true;

        batchHistory[_batchId].push(Checkpoint({
            timestamp: block.timestamp,
            location: "",
            handler: msg.sender,
            status: batches[_batchId].status,
            notes: "Certified by regulator"
        }));

        emit BatchCertified(_batchId, msg.sender);
    }

    // =========================================================================
    //  View Συναρτήσεις (Ανάγνωση δεδομένων)
    // =========================================================================

    /**
     * @notice Επιστρέφει τα στοιχεία μιας παρτίδας.
     */
    function getBatch(uint256 _batchId) external view returns (Batch memory) {
        require(_batchId > 0 && _batchId <= batchCount, "Batch does not exist");
        return batches[_batchId];
    }

    /**
     * @notice Επιστρέφει το ιστορικό checkpoints μιας παρτίδας.
     */
    function getBatchHistory(uint256 _batchId) external view returns (Checkpoint[] memory) {
        require(_batchId > 0 && _batchId <= batchCount, "Batch does not exist");
        return batchHistory[_batchId];
    }

    /**
     * @notice Επιστρέφει τα στοιχεία ενός χρήστη.
     */
    function getUser(address _userAddress) external view returns (User memory) {
        return users[_userAddress];
    }

    /**
     * @notice Επιστρέφει τον αριθμό των checkpoints μιας παρτίδας.
     */
    function getBatchHistoryCount(uint256 _batchId) external view returns (uint256) {
        return batchHistory[_batchId].length;
    }

    /**
     * @notice Επιστρέφει όλα τα IDs παρτίδων.
     */
    function getAllBatchIds() external view returns (uint256[] memory) {
        return batchIds;
    }

    /**
     * @notice Επιστρέφει όλες τις διευθύνσεις χρηστών.
     */
    function getAllUserAddresses() external view returns (address[] memory) {
        return userAddresses;
    }

    /**
     * @notice Επιστρέφει τον αριθμό εγγεγραμμένων χρηστών.
     */
    function getUserCount() external view returns (uint256) {
        return userAddresses.length;
    }
}

